/**
 * MedX darkmode theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Dark theme overrides and contrast pairs.
 */
const DARKMODE_TOKENS = Object.freeze({
  primary: { value: "theme-darkmode-primary", scope: "theme" },
  secondary: { value: "theme-darkmode-secondary", scope: "theme" },
  muted: { value: "theme-darkmode-muted", scope: "theme" },
  accent: { value: "theme-darkmode-accent", scope: "theme" },
  surface: { value: "theme-darkmode-surface", scope: "theme" },
});

const DARKMODE_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const DARKMODE_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const darkmodeRegistry = new Map();
const DARKMODE_listeners = new Set();
let DARKMODE_seq = 0;

function createDarkmodeId(prefix = "medx-theme-darkmode") {
  DARKMODE_seq += 1;
  return `${prefix}-${DARKMODE_seq}`;
}

function registerDarkmode(config = {}) {
  const entryId = config.id ?? createDarkmodeId();
  const preset = DARKMODE_PRESETS[config.preset ?? "default"] ?? DARKMODE_PRESETS.default;
  const token = DARKMODE_TOKENS[config.token ?? preset.token] ?? DARKMODE_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: DARKMODE_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  darkmodeRegistry.set(entryId, entry);
  notifyDarkmodeListeners("register", entry);
  return entry;
}

function updateDarkmode(id, patch = {}) {
  const entry = darkmodeRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyDarkmodeListeners("update", entry);
  return entry;
}

function resolveDarkmode(id) {
  const entry = darkmodeRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listDarkmodeEntries(filter = {}) {
  let items = Array.from(darkmodeRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onDarkmodeEvent(listener) {
  DARKMODE_listeners.add(listener);
  return () => DARKMODE_listeners.delete(listener);
}

function notifyDarkmodeListeners(type, entry) {
  for (const listener of DARKMODE_listeners) {
    try {
      listener({ type, entry, registrySize: darkmodeRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:darkmode] listener error", err.message);
    }
  }
}

function getDarkmodeMetrics() {
  const items = listDarkmodeEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(DARKMODE_TOKENS).length,
    presets: Object.keys(DARKMODE_PRESETS).length,
  };
}

async function runMedxDarkmode() {
  console.log("[medx:ui:theme:darkmode] runtime initialized");
  console.log(`[medx:ui:theme:darkmode] tokens=${Object.keys(DARKMODE_TOKENS).length} presets=${Object.keys(DARKMODE_PRESETS).length}`);

  const events = [];
  onDarkmodeEvent((e) => events.push(e.type));

  const domains = Object.keys(DARKMODE_SUPPLY_CHAIN);
  const presets = Object.keys(DARKMODE_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerDarkmode({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/darkmode" },
    });
  }

  const first = listDarkmodeEntries()[0];
  if (first) updateDarkmode(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getDarkmodeMetrics();
  const resolved = first ? resolveDarkmode(first.id) : null;

  console.log(`[medx:ui:theme:darkmode] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:darkmode] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:darkmode] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:darkmode] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:darkmode] bootstrap complete");
}

module.exports = runMedxDarkmode;
